:root {
    --primary-color: #5c6bc0;
    --secondary-color: #ed64a6;
    --background-color: #ffffff;
    --text-color: #2f4f7f;
    --font-heading: 'Space Grotesk', sans-serif;
    --font-body: 'Inter', sans-serif;
    --spacing-small: 8px;
    --spacing-medium: 16px;
    --spacing-large: 24px;
}

body {
    font-family: var(--font-body);
    margin: 0;
    padding: 0;
    background-color: var(--background-color);
    color: var(--text-color);
    line-height: 1.6;
}

h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-heading);
    margin-bottom: var(--spacing-small);
}

.navbar {
    background-color: var(--primary-color);
    color: #ffffff;
    padding: var(--spacing-small);
    display: flex;
    justify-content: space-between;
    align-items: center;
    position: sticky;
    top: 0;
}

.navbar nav ul {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
}

.navbar nav ul li {
    margin-right: var(--spacing-small);
}

.navbar nav a {
    color: #ffffff;
    text-decoration: none;
}

.navbar nav a:hover {
    color: var(--secondary-color);
}

.hero-section {
    background-image: linear-gradient(to bottom, var(--primary-color), var(--secondary-color));
    background-size: 100% 300px;
    background-position: 0% 100%;
    height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    color: #ffffff;
}

.hero-section h1 {
    font-size: 48px;
}

.btn {
    background-color: var(--primary-color);
    color: #ffffff;
    border: none;
    padding: var(--spacing-small) var(--spacing-medium);
    font-size: 18px;
    cursor: pointer;
}

.btn:hover {
    background-color: var(--secondary-color);
}

.featured-products {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--spacing-medium);
    padding: var(--spacing-medium);
}

.featured-products .grid-item {
    background-color: #f7f7f7;
    padding: var(--spacing-small);
    border: 1px solid #dddddd;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
}

.featured-products .grid-item img {
    width: 100%;
    height: 150px;
    object-fit: cover;
    border-radius: 10px 10px 0 0;
}

.featured-products .grid-item h3 {
    font-size: 18px;
    margin-bottom: var(--spacing-small);
}

.categories {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--spacing-medium);
    padding: var(--spacing-medium);
}

.categories .category-item {
    background-color: #f7f7f7;
    padding: var(--spacing-small);
    border: 1px solid #dddddd;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
}

.categories .category-item img {
    width: 100%;
    height: 150px;
    object-fit: cover;
    border-radius: 10px 10px 0 0;
}

.testimonials {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--spacing-medium);
    padding: var(--spacing-medium);
}

.testimonials .testimonial-item {
    background-color: #f7f7f7;
    padding: var(--spacing-small);
    border: 1px solid #dddddd;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
}

.testimonials .testimonial-item img {
    width: 100%;
    height: 150px;
    object-fit: cover;
    border-radius: 10px 10px 0 0;
}

.call-to-action {
    background-image: linear-gradient(to bottom, var(--primary-color), var(--secondary-color));
    background-size: 100% 300px;
    background-position: 0% 100%;
    height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    color: #ffffff;
}

.call-to-action h2 {
    font-size: 48px;
}

footer {
    background-color: var(--primary-color);
    color: #ffffff;
    padding: var(--spacing-small);
    text-align: center;
}

footer ul {
    list-style: none;
    margin: 0;
    padding: 0;
}

footer ul li {
    margin-bottom: var(--spacing-small);
}

footer a {
    color: #ffffff;
    text-decoration: none;
}

footer a:hover {
    color: var(--secondary-color);
}

.social-links {
    margin-top: var(--spacing-medium);
}

.social-links a {
    margin-right: var(--spacing-small);
}

.social-links svg {
    width: 24px;
    height: 24px;
}

@media (max-width: 768px) {
    .featured-products {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 480px) {
    .featured-products {
        grid-template-columns: repeat(1, 1fr);
    }
    .categories {
        grid-template-columns: repeat(1, 1fr);
    }
    .testimonials {
        grid-template-columns: repeat(1, 1fr);
    }
}

